import { NextResponse } from "next/server";

import { listDistributors } from "@/lib/db/store";
import { getSession } from "@/lib/auth/session";

export const dynamic = "force-dynamic";

export async function GET(): Promise<Response> {
  const session = getSession();
  if (!session) {
    return NextResponse.json({ error: "unauthenticated" }, { status: 401 });
  }
  const distributors = listDistributors().map((d) => ({
    id: d.id,
    name: d.name,
    region: d.region,
    rating: d.rating,
  }));
  return NextResponse.json({ distributors });
}

import { NextResponse } from "next/server";

import { getDistributor, searchMedicines } from "@/lib/db/store";
import { getSession } from "@/lib/auth/session";

export const dynamic = "force-dynamic";

export async function GET(request: Request): Promise<Response> {
  const session = getSession();
  if (!session) {
    return NextResponse.json({ error: "unauthenticated" }, { status: 401 });
  }
  const { searchParams } = new URL(request.url);
  const q = searchParams.get("q") ?? "";
  const meds = searchMedicines(q).slice(0, 50);
  const results = meds.map((m) => {
    const d = getDistributor(m.distributorId);
    return {
      id: m.id,
      name: m.name,
      brand: m.brand,
      genericName: m.genericName,
      distributor: d
        ? { id: d.id, name: d.name }
        : { id: m.distributorId, name: "Unknown distributor" },
      mrpPaise: m.mrpPaise,
      sellingPricePaise: m.sellingPricePaise,
      scheme: m.scheme,
      packSize: m.packSize,
    };
  });
  return NextResponse.json({ results });
}

import { NextResponse } from "next/server";

import { getDistributor, listOffers } from "@/lib/db/store";
import { getSession } from "@/lib/auth/session";

export const dynamic = "force-dynamic";

export async function GET(): Promise<Response> {
  const session = getSession();
  if (!session) {
    return NextResponse.json({ error: "unauthenticated" }, { status: 401 });
  }
  const offers = listOffers().map((o) => {
    const d = getDistributor(o.distributorId);
    return {
      id: o.id,
      title: o.title,
      description: o.description,
      bannerLabel: o.bannerLabel,
      validUntil: o.validUntil.toISOString(),
      distributor: d
        ? { id: d.id, name: d.name }
        : { id: o.distributorId, name: "Unknown distributor" },
    };
  });
  return NextResponse.json({ offers });
}

